use base64::{engine::general_purpose::STANDARD as BASE64_STANDARD, Engine as _};
use distributed_inference::app_streaming::{AppState, HolographicAppBridge};
use distributed_inference::holographic_reconstruction::{
    ProjectionView, SovereignSieve, VoxelCoord,
};
use distributed_inference::pleromatic_frame::{PleromaticFrame, PleromaticMediaType, SignalToken};
use distributed_inference::voice_codecs::{self, ProsodyFrame};
use std::collections::HashMap;

#[test]
fn test_pleromatic_frame_unification() {
    // Proves we can pack and unpack all required media types.
    let media_types = vec![
        PleromaticMediaType::Video,
        PleromaticMediaType::Audio,
        PleromaticMediaType::Semantic,
        PleromaticMediaType::Fingerprint,
        PleromaticMediaType::Application,
    ];

    for mt in media_types {
        let frame = PleromaticFrame::grounding("test-node".into(), mt.clone(), vec![1, 2, 3]);
        let serialized = serde_json::to_string(&frame).expect("Should serialize");
        let deserialized: PleromaticFrame =
            serde_json::from_str(&serialized).expect("Should deserialize");
        assert_eq!(deserialized.media_type, mt);
    }
}

#[test]
fn test_holographic_reconstruction_flow() {
    // Proves the Sovereign Sieve can re-inflate 3D logic from 2D projections.
    let mut sieve = SovereignSieve::new(10, 10, 10);

    // Create 3 views of a single point in the center (5, 5, 5).
    let mut views = Vec::new();
    for i in 0..3 {
        let angle = i as f32 * 2.0 * std::f32::consts::PI / 3.0;
        let mut frame_data = vec![0u8; 100];

        // Find where (5,5,5) projects in this view.
        let coord = VoxelCoord { x: 5, y: 5, z: 5 };
        let view_stub = ProjectionView {
            view_id: format!("v{}", i),
            angle_rad: angle,
            frame_data: Vec::new(),
            width: 10,
            height: 10,
        };
        let (u, v) = distributed_inference::holographic_reconstruction::VirtualShutter::project(
            coord,
            &view_stub,
            VoxelCoord {
                x: 10,
                y: 10,
                z: 10,
            },
        );
        frame_data[v * 10 + u] = 255;

        views.push(ProjectionView {
            view_id: format!("v{}", i),
            angle_rad: angle,
            frame_data,
            width: 10,
            height: 10,
        });
    }

    sieve.reconstruct(&views);

    // The center voxel should be verified.
    let center = VoxelCoord { x: 5, y: 5, z: 5 };
    assert!(sieve.space.voxels.contains_key(&center));
    assert!(sieve.space.voxels.get(&center).unwrap().is_path);
}

#[test]
fn test_voice_codec_integration() {
    // Proves Pneuma voice codecs can be transported via PleromaticFrame.

    // 1. Phonemes
    let phonemes = vec![1, 30, 34, 36];
    let p_packet = voice_codecs::encode_phonemes(&phonemes);
    let p_frame =
        PleromaticFrame::grounding("voice-node".into(), PleromaticMediaType::Audio, p_packet);

    let decoded_p = voice_codecs::decode_phonemes(&p_frame.data);
    assert_eq!(phonemes, decoded_p);

    // 2. Prosody
    let prosody = vec![ProsodyFrame {
        f0_bin: 32,
        energy_bin: 32,
    }];
    let pr_packet = voice_codecs::encode_prosody(&prosody);
    let pr_frame =
        PleromaticFrame::grounding("voice-node".into(), PleromaticMediaType::Audio, pr_packet);

    let decoded_pr = voice_codecs::decode_prosody(&pr_frame.data);
    assert_eq!(prosody, decoded_pr);
}

#[test]
fn test_application_streaming_integration() {
    // Proves app state and logic can be bundled into a single frame.
    let mut bridge = HolographicAppBridge::new("demo-app");
    let mut components = HashMap::new();
    components.insert("active_view".into(), "dashboard".into());

    let state = AppState {
        app_id: "demo-app".into(),
        components,
        active_coords: vec![VoxelCoord {
            x: 10,
            y: 10,
            z: 10,
        }],
    };
    let logic = vec![SignalToken::T, SignalToken::S, SignalToken::V];

    let frame = bridge.capture_frame(&state, logic.clone());

    // Unpack on "client" side
    let decoded_state: AppState = bincode::deserialize(&frame.data).unwrap();
    assert_eq!(decoded_state.app_id, "demo-app");
    assert_eq!(
        decoded_state.active_coords[0],
        VoxelCoord {
            x: 10,
            y: 10,
            z: 10
        }
    );

    let logic_b64 = frame.attributes.get("logic_path").unwrap();
    let logic_bytes = BASE64_STANDARD.decode(logic_b64).unwrap();
    let decoded_logic: Vec<SignalToken> = bincode::deserialize(&logic_bytes).unwrap();
    assert_eq!(logic, decoded_logic);
}

#[test]
fn test_semantic_embedding_transport() {
    // Proves last-layer residuals can be transported correctly.
    let mut data = Vec::new();
    for i in 0..10 {
        data.extend_from_slice(&(i as f32 * 0.1).to_le_bytes());
    }

    let mut frame =
        PleromaticFrame::grounding("llm-node".into(), PleromaticMediaType::Semantic, data);
    frame.attributes.insert("hidden_dim".into(), "10".into());

    assert_eq!(frame.data.len(), 40);
    assert_eq!(frame.attributes.get("hidden_dim").unwrap(), "10");
}
